import { useState } from "react";
import { useNavigate } from "react-router-dom";
import {
  Box,
  TextField,
  Button,
  Typography,
  Card,
  CardContent,
} from "@mui/material";
import API from "../../api/axios";
import Topbar from "../../layouts/Topbar"; // 🔥 ADD THIS

export default function CreateAdmin() {
  const [form, setForm] = useState({
    organization: "",
    username: "",
    password: "",
    newPassword: "",
  });

  const navigate = useNavigate();

  const createAdmin = async () => {
    try {
      await API.post("create-admin/", {
        username: form.username,
        password: form.password,
        organization: form.organization, // 🔥 ADD THIS
      });

      alert("Admin + Organization created ✅");
    } catch {
      alert("Error ❌");
    }
  };

  const changePassword = async () => {
    try {
      await API.post("change-password/", {
        username: form.username,
        new_password: form.newPassword,
      });
      alert("Password changed ✅");
    } catch {
      alert("Failed ❌");
    }
  };

  return (
    <>
      {/* 🔥 TOPBAR */}
      <Topbar />

      {/* 🔥 MAIN CONTAINER */}
      <Box
        sx={{
          pt: 12, // 🔥 IMPORTANT (topbar spacing)
          height: "100vh",
          background: "linear-gradient(135deg, #1e3c72, #2a5298)",
          display: "flex",
          justifyContent: "center",
          alignItems: "center",
        }}
      >
        <Card
          sx={{
            width: 420,
            borderRadius: 4,
            backdropFilter: "blur(15px)",
            background: "rgba(255,255,255,0.1)",
            color: "#fff",
            boxShadow: "0 20px 40px rgba(0,0,0,0.4)",
            transform: "perspective(1000px) rotateX(5deg)",
          }}
        >
          <CardContent>
            <Typography variant="h5" textAlign="center" mb={2}>
              🚀 Create Admin
            </Typography>

            <TextField
              fullWidth
              label="Organization Name"
              margin="normal"
              InputLabelProps={{ style: { color: "#fff" } }}
              sx={{ input: { color: "#fff" } }}
              onChange={(e) =>
                setForm({ ...form, organization: e.target.value })
              }
            />

            <TextField
              fullWidth
              label="Username"
              margin="normal"
              InputLabelProps={{ style: { color: "#fff" } }}
              sx={{ input: { color: "#fff" } }}
              onChange={(e) => setForm({ ...form, username: e.target.value })}
            />

            <TextField
              fullWidth
              label="Password"
              type="password"
              margin="normal"
              InputLabelProps={{ style: { color: "#fff" } }}
              sx={{ input: { color: "#fff" } }}
              onChange={(e) => setForm({ ...form, password: e.target.value })}
            />

            {/* 🔥 Change Password */}
            <Typography mt={2} fontSize={14}>
              Change Password
            </Typography>

            <TextField
              fullWidth
              label="New Password"
              type="password"
              margin="normal"
              InputLabelProps={{ style: { color: "#fff" } }}
              sx={{ input: { color: "#fff" } }}
              onChange={(e) =>
                setForm({ ...form, newPassword: e.target.value })
              }
            />

            <Button
              fullWidth
              variant="outlined"
              sx={{ mt: 1, color: "#fff", borderColor: "#fff" }}
              onClick={changePassword}
            >
              Change Password
            </Button>

            {/* 🔥 Buttons */}
            <Box sx={{ display: "flex", gap: 2, mt: 3 }}>
              <Button
                fullWidth
                variant="contained"
                onClick={createAdmin}
                sx={{
                  background: "linear-gradient(45deg, #00c6ff, #0072ff)",
                }}
              >
                Create Admin
              </Button>

              <Button
                fullWidth
                variant="outlined"
                sx={{ color: "#fff", borderColor: "#fff" }}
                onClick={() => navigate("/superadmin/org-list")}
              >
                Organization List
              </Button>
            </Box>
          </CardContent>
        </Card>
      </Box>
    </>
  );
}
